// Precision L-bracket — BREP/replicad showcase
// Two legs forming an L, with selective fillets:
//   • inside concave web (where the legs meet) filleted 5 mm — the signature
//   • outside tip edges of each leg's free end, rounded 2.5 mm
// All rounding applied BEFORE drilling mounting holes (per replicad.md).
const { BREP } = api;

// Dimensions
const LEG_LEN = 60;     // length of each leg from the corner
const WIDTH   = 50;     // depth (Y) of the bracket
const THICK   = 6;      // wall thickness

const horizLeg = BREP.box([LEG_LEN, WIDTH, THICK]);
const vertLeg  = BREP.box([THICK, WIDTH, LEG_LEN]);

// Fuse into the L. The corner cube (THICK × WIDTH × THICK) is shared —
// replicad merges the coplanar inside faces, leaving a clean L-prism.
let bracket = horizLeg.fuse(vertLeg);

// --- Selective fillets, applied BEFORE any cuts. ---
// Every edge we want to round is parallel to +Y. Replicad's `inBox` filter
// proved finicky on these long Y-parallel edges, so we lean on `inDirection`
// combined with a single-axis range to pick each one.

const Y_DIR = [0, 1, 0];

// 1. THE signature feature: inside concave web edge at (X=THICK, Z=THICK).
//    Use nearPoint here — `inDirection + minZ/maxZ at Z=6` would also catch
//    the convex top-of-horizontal-leg edge at X=LEG_LEN, Z=THICK, which we
//    DON'T want filleted at 5 mm (the top face is only 6 mm wide).
bracket = bracket.fillet(5, {
  nearPoint: [THICK, WIDTH / 2, THICK],
  withinDist: 0.5,
});

// 2. Outside tip of the horizontal leg — Y-parallel edge at X=LEG_LEN, Z=0.
//    Only Y-parallel edge with Z≤0 on the L (the inside-bottom corner is
//    absorbed because both legs touch Z=0 along the same face). Radius
//    capped at 2.5 (leg is 6 mm thick — going larger fails the solver).
bracket = bracket.fillet(2.5, {
  inDirection: Y_DIR,
  maxZ: 0.01,
});

// 3. Outside tip of the vertical leg — Y-parallel edge at X=0, Z=LEG_LEN.
//    Only Y-parallel edge with X≤0.
bracket = bracket.fillet(2.5, {
  inDirection: Y_DIR,
  maxX: 0.01,
});

// (Top-of-leg chamfers were attempted here but replicad's EdgeFilter
// reliably refused every targeting strategy on the post-fillet edge graph;
// dropped to keep the model bulletproof. The signature concave fillet and
// the two outer-tip fillets carry the showcase.)

// --- Mounting holes (drilled AFTER all rounding). ---
const HOLE_R = 2.5;            // 5 mm diameter
const HOLE_INSET_AXIAL = 15;   // distance along the leg from the free end
const HOLE_INSET_Y     = 12;   // distance from each Y face

const holes = [];

// Horizontal leg: drill top-down (default Z-axis cylinder).
for (const y of [HOLE_INSET_Y, WIDTH - HOLE_INSET_Y]) {
  holes.push(
    BREP.cylinder(HOLE_R, THICK + 2)
      .translate([LEG_LEN - HOLE_INSET_AXIAL, y, -1])
  );
}

// Vertical leg: drill horizontally through THICK. Rotate cylinder +90°
// about Y so its axis points along +X.
for (const y of [HOLE_INSET_Y, WIDTH - HOLE_INSET_Y]) {
  holes.push(
    BREP.cylinder(HOLE_R, THICK + 2)
      .rotate(90, [0, 1, 0])
      .translate([-1, y, LEG_LEN - HOLE_INSET_AXIAL])
  );
}

return BREP.cutAll([bracket, ...holes]);
